module top_module(
  input        clk,
  input        reset,
  input  [15:0] input_signal,
  output [3:0] output_signal
);reg [3:0] upper_bits;

  always @(posedge clk, negedge reset) begin
    if (reset == 0) begin
      upper_bits <= 4'b0;
    end else begin
      upper_bits <= input_signal[15:12];
    end
  end

  assign output_signal = upper_bits;

endmodule
